using Dalamud.Interface.Components;namespace TidyChat.Settings.Tabs;internal static class CombatTab{    public static void Draw(Configuration configuration)    {        SettingsTabLayout.DrawTabNote(Languages.CombatTab_FilteringNote);        SettingsTabLayout.DrawSections(true,            (Languages.CombatTab_CastingAndAbilitiesDropdownHeader, () => DrawCastingAndAbilities(configuration)),            (Languages.CombatTab_DamageHealingAndEffectsDropdownHeader, () => DrawDamageHealingAndEffects(configuration)),            (Languages.CombatTab_DefeatAndAddsDropdownHeader, () => DrawDefeatAndAdds(configuration)));    }    private static void DrawCastingAndAbilities(Configuration configuration)    {        var showCombatCasting = configuration.ShowCombatCasting;        if (ImGui.Checkbox(Languages.CombatTab_ShowCombatCastingMessages, ref showCombatCasting))        {            configuration.ShowCombatCasting = showCombatCasting;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.CombatTab_ShowCombatCastingMessagesHelpMarker);        var showCombatAbilities = configuration.ShowCombatAbilities;        if (ImGui.Checkbox(Languages.CombatTab_ShowCombatAbilitiesMessages, ref showCombatAbilities))        {            configuration.ShowCombatAbilities = showCombatAbilities;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.CombatTab_ShowCombatAbilitiesMessagesHelpMarker);    }    private static void DrawDamageHealingAndEffects(Configuration configuration)    {        var showCombatDamage = configuration.ShowCombatDamage;        if (ImGui.Checkbox(Languages.CombatTab_ShowCombatDamageMessages, ref showCombatDamage))        {            configuration.ShowCombatDamage = showCombatDamage;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.CombatTab_ShowCombatDamageMessagesHelpMarker);        var showCombatMisses = configuration.ShowCombatMisses;        if (ImGui.Checkbox(Languages.CombatTab_ShowCombatMissesMessages, ref showCombatMisses))        {            configuration.ShowCombatMisses = showCombatMisses;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.CombatTab_ShowCombatMissesMessagesHelpMarker);        var showCombatHealing = configuration.ShowCombatHealing;        if (ImGui.Checkbox(Languages.CombatTab_ShowCombatHealingMessages, ref showCombatHealing))        {            configuration.ShowCombatHealing = showCombatHealing;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.CombatTab_ShowCombatHealingMessagesHelpMarker);        var showCombatEffects = configuration.ShowCombatEffects;        if (ImGui.Checkbox(Languages.CombatTab_ShowCombatEffectsMessages, ref showCombatEffects))        {            configuration.ShowCombatEffects = showCombatEffects;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.CombatTab_ShowCombatEffectsMessagesHelpMarker);    }    private static void DrawDefeatAndAdds(Configuration configuration)    {        var showCombatDefeat = configuration.ShowCombatDefeat;        if (ImGui.Checkbox(Languages.CombatTab_ShowCombatDefeatMessages, ref showCombatDefeat))        {            configuration.ShowCombatDefeat = showCombatDefeat;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.CombatTab_ShowCombatDefeatMessagesHelpMarker);        var showCombatEnemyReady = configuration.ShowCombatEnemyReady;        if (ImGui.Checkbox(Languages.CombatTab_ShowCombatEnemyReadyMessages, ref showCombatEnemyReady))        {            configuration.ShowCombatEnemyReady = showCombatEnemyReady;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.CombatTab_ShowCombatEnemyReadyMessagesHelpMarker);        var showCombatAdds = configuration.ShowCombatAdds;        if (ImGui.Checkbox(Languages.CombatTab_ShowCombatAddsMessages, ref showCombatAdds))        {            configuration.ShowCombatAdds = showCombatAdds;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.CombatTab_ShowCombatAddsMessagesHelpMarker);        var showCombatEnmity = configuration.ShowCombatEnmity;        if (ImGui.Checkbox(Languages.CombatTab_ShowCombatEnmityMessages, ref showCombatEnmity))        {            configuration.ShowCombatEnmity = showCombatEnmity;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.CombatTab_ShowCombatEnmityMessagesHelpMarker);    }}